/**
 * @summary Get shopping list for a date
 */
export const getGetShoppingListUrl = (params?: GetShoppingListParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/shopping-list?${stringifiedParams}`
    : `/api/shopping-list`;
};

export const getShoppingList = async (
  params?: GetShoppingListParams,
  options?: RequestInit,
): Promise<ShoppingListResponse> => {
  return customFetch<ShoppingListResponse>(getGetShoppingListUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetShoppingListQueryKey = (params?: GetShoppingListParams) => {
  return [`/api/shopping-list`, ...(params ? [params] : [])] as const;
};

export const getGetShoppingListQueryOptions = <
  TData = Awaited<ReturnType<typeof getShoppingList>>,
  TError = ErrorType<ErrorEnvelope>,
>(
  params?: GetShoppingListParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getShoppingList>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetShoppingListQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getShoppingList>>> = ({
    signal,
  }) => getShoppingList(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getShoppingList>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetShoppingListQueryResult = NonNullable<
  Awaited<ReturnType<typeof getShoppingList>>
>;
export type GetShoppingListQueryError = ErrorType<ErrorEnvelope>;

